#!/usr/bin/env node
// E2E tests -- auto-generated by Clear compiler
// Run: node test.js
// Requires: server running on localhost:3000

const BASE = process.env.TEST_URL || "http://localhost:3000";
let passed = 0, failed = 0;
let _emailCounter = 0;
let _uniqueCounter = 0;
let _response, _responseBody;
let _lastCall = { method: "", path: "", line: 0 };
function _uniqueEmail() { return "test" + (++_emailCounter) + "@example.com"; }
function _uniqueText(base) { return base + "_" + (++_uniqueCounter); }

// Note: for clean re-runs, delete clear-data.db before starting the server
// unique constraints may cause 500s if stale data exists from a previous run

async function test(name, fn) {
  try {
    await fn();
    passed++;
    console.log("PASS:", name);
  } catch (err) {
    failed++;
    console.log("FAIL:", name, "-", err.message);
  }
}

function assert(condition, msg) { if (!condition) throw new Error(msg); }

async function run() {
  await test("Creating a new register succeeds", async () => {
    const payload = {"email":"test@example.com","password":"Test value","name":"Test value"};
    payload["email"] = _uniqueEmail();
    payload["password"] = _uniqueText("password");
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/register", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("Creating a register without any data is rejected", async () => {
    const r = await fetch(BASE + "/api/register", { method: "POST" });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("Creating a register with a blank email is rejected", async () => {
    const r = await fetch(BASE + "/api/register", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("Creating a register with a name that's too long is rejected", async () => {
    const r = await fetch(BASE + "/api/register", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: "xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("Extra fields are stripped when creating a register", async () => {
    const payload = { ...{"email":"test@example.com","password":"Test value","name":"Test value"}, admin: true, role: "superuser" };
    payload["email"] = _uniqueEmail();
    payload["password"] = _uniqueText("password");
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/register", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.admin === undefined, "admin field should have been stripped");
    assert(data.role === undefined, "role field should have been stripped");
  });

  console.log("");
  console.log("Results:", passed, "passed,", failed, "failed");
  process.exit(failed > 0 ? 1 : 0);
}

run();